import React, { useState, useEffect } from 'react';
import api from '../../services/api';
import { FiUsers, FiCalendar, FiClock, FiUserCheck } from 'react-icons/fi';
import { useNavigate } from 'react-router-dom';

const Dashboard = () => {
  const [data, setData] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    api.get('/dashboard').then(res => setData(res.data)).catch(() => {});
  }, []);

  if (!data) return <div className="loading-screen"><div className="spinner"></div></div>;

  return (
    <div>
      <div className="stats-grid">
        <div className="stat-card">
          <div className="stat-icon" style={{ background: '#fff3e0', color: '#ff7b1d' }}><FiUsers /></div>
          <div className="stat-info"><h4>{data.employeeCount}</h4><p>Total Employees</p></div>
        </div>
        <div className="stat-card">
          <div className="stat-icon" style={{ background: '#e8f5e9', color: '#2e7d32' }}><FiCalendar /></div>
          <div className="stat-info"><h4>{data.pendingLeaves?.length || 0}</h4><p>Pending Leave</p></div>
        </div>
        <div className="stat-card">
          <div className="stat-icon" style={{ background: '#e3f2fd', color: '#1565c0' }}><FiClock /></div>
          <div className="stat-info">
            <h4>{data.employeesOnLeave?.length || 0}</h4>
            <p>On Leave Today</p>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon" style={{ background: '#f3e5f5', color: '#7b1fa2' }}><FiUserCheck /></div>
          <div className="stat-info"><h4>{data.candidateCount}</h4><p>Candidates</p></div>
        </div>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 20 }}>
        <div className="card">
          <div className="card-header"><h3>Pending Leave Requests</h3></div>
          <div className="card-body">
            {data.pendingLeaves?.length === 0 ? (
              <p style={{ color: '#999', fontSize: 13 }}>No pending leave requests.</p>
            ) : (
              <div className="table-container">
                <table>
                  <thead><tr><th>Employee</th><th>Type</th><th>Dates</th><th></th></tr></thead>
                  <tbody>
                    {data.pendingLeaves?.slice(0, 5).map(l => (
                      <tr key={l._id}>
                        <td>{l.employee?.fullName}</td>
                        <td><span className="status-badge status-pending">{l.leaveType?.name}</span></td>
                        <td>{new Date(l.fromDate).toLocaleDateString()} - {new Date(l.toDate).toLocaleDateString()}</td>
                        <td>
                          <button className="btn btn-sm btn-primary" onClick={() => navigate('/leave/requests')}>Review</button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        </div>

        <div className="card">
          <div className="card-header"><h3>Buzz Latest Posts</h3></div>
          <div className="card-body">
            {data.recentBuzz?.length === 0 ? (
              <p style={{ color: '#999', fontSize: 13 }}>No buzz posts yet.</p>
            ) : (
              data.recentBuzz?.slice(0, 3).map(post => (
                <div key={post._id} style={{ padding: '8px 0', borderBottom: '1px solid #f0f0f0' }}>
                  <strong>{post.employee?.fullName}</strong>
                  <p style={{ fontSize: 13, marginTop: 4 }}>{post.content}</p>
                  <small style={{ color: '#999' }}>{new Date(post.createdAt).toLocaleString()}</small>
                </div>
              ))
            )}
            <button className="btn btn-sm btn-outline" style={{ marginTop: 12 }} onClick={() => navigate('/buzz')}>View All Posts</button>
          </div>
        </div>
      </div>

      <div className="card" style={{ marginTop: 20 }}>
        <div className="card-header"><h3>Employees On Leave Today</h3></div>
        <div className="card-body">
          {data.employeesOnLeave?.length === 0 ? (
            <p style={{ color: '#999', fontSize: 13 }}>No employees on leave today.</p>
          ) : (
            <div className="table-container">
              <table>
                <thead><tr><th>Name</th><th>Department</th></tr></thead>
                <tbody>
                  {data.employeesOnLeave?.map(l => (
                    <tr key={l._id}><td>{l.employee?.fullName}</td><td>{l.employee?.department || '-'}</td></tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
